const promise = new Promise((resolve, reject) => {
  // Perform the async work here.
  // Call resolve(value) on success:
  resolve(42);
  // Call reject(reason) on failure:
  // reject(new Error('something went wrong'));
});

// In practice you rarely construct promises by hand —
// browser APIs such as fetch() return them for you.

// Each .then() receives what the previous one returned:
fetch('/api/posts/1')
  .then(res => {
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    return res.json();          // returning a Promise is fine — the chain waits for it
  })
  .then(post => {
    console.log(post.title);
    return fetch(`/api/users/${post.authorId}`); // chain a second request
  })
  .then(res => res.json())
  .then(author => console.log(author.name))
  .catch(err => {
    // Any rejection from any step above lands here:
    console.error('Failed:', err.message);
  });

// Already-fulfilled:
Promise.resolve(42).then(n => console.log(n)); // 42

// Already-rejected:
Promise.reject(new Error('not found')).catch(e => console.error(e.message)); // 'not found'

// Useful in a function that must always return a Promise:
function getUser(id) {
  if (cache.has(id)) {
    return Promise.resolve(cache.get(id)); // synchronous hit, async interface
  }
  return fetch(`/api/users/${id}`).then(r => r.json());
}

// ❌ Rejection is silently swallowed if the parse fails:
fetch('/api/data').then(res => res.json()).then(data => process(data));

// ✅ Always end with .catch():
fetch('/api/data')
  .then(res => res.json())
  .then(data => process(data))
  .catch(err => handleError(err));

// ✅ .catch() can recover — returning a value resumes the chain as fulfilled:
fetch('/api/data')
  .then(res => res.json())
  .catch(() => ({ items: [] }))  // fallback value on failure
  .then(data => render(data));   // runs with real data or the fallback

import { useState, useEffect } from 'react';

function UserProfile({ userId }) {
  const [user, setUser]       = useState(null);
  const [error, setError]     = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let cancelled = false; // guard against setting state after unmount

    fetch(`/api/users/${userId}`)
      .then(res => {
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        return res.json();
      })
      .then(data => {
        if (!cancelled) setUser(data);
      })
      .catch(err => {
        if (!cancelled) setError(err.message);
      })
      .finally(() => {
        if (!cancelled) setLoading(false);
      });

    return () => { cancelled = true; }; // cleanup on unmount or userId change
  }, [userId]);

  if (loading) return <p>Loading…</p>;
  if (error)   return <p>Error: {error}</p>;
  return <h1>{user.name}</h1>;
}
